import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjRefresher } from "./OjRefresher";
export { OjRefresher };

/**
 * Create an instance of [[OjRefresher]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojRefresher(driver, By.id('my-oj-refresher'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojRefresher(driver: DriverLike, by: By): Promise<OjRefresher> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjRefresher
  if (!(webEl instanceof OjRefresher)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-refresher>`);
  }
  return webEl;
}

register("oj-refresher", OjRefresher);
